-- MMS Database Extensions Migration
-- Enables required PostgreSQL extensions
--
-- Run order: 1 (must run before any schema migrations)
-- Requires: superuser privileges

-- UUID generation for primary keys
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- TimescaleDB for time-series mileage data
-- Note: Must be installed on PostgreSQL server first
CREATE EXTENSION IF NOT EXISTS timescaledb CASCADE;

-- Verify extensions are installed
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'uuid-ossp') THEN
        RAISE EXCEPTION 'uuid-ossp extension not installed';
    END IF;

    IF NOT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'timescaledb') THEN
        RAISE EXCEPTION 'timescaledb extension not installed';
    END IF;

    RAISE NOTICE 'All required extensions installed successfully';
END $$;

-- MMS Database Functions & Triggers Migration
-- Business logic implemented at database level for consistency
--
-- Run order: 3 (after schema creation)
-- @see specs/003-database-schema.md Section 3.6

-- =============================================================================
-- HELPER FUNCTIONS
-- =============================================================================

-- updated_at trigger function (reusable)
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- =============================================================================
-- TRAIN FITNESS SYNC FROM UNAVAILABILITY EVENTS
-- =============================================================================

-- Automatically update train.fitness_status when unavailability events change
-- Priority: GROUNDED > RESTRICTED > FIT
CREATE OR REPLACE FUNCTION sync_train_fitness_from_unavailability()
RETURNS TRIGGER AS $$
DECLARE
    has_grounded BOOLEAN;
    has_restricted BOOLEAN;
    new_status fitness_status;
BEGIN
    -- Determine train ID to update
    -- Handle both INSERT/UPDATE (NEW) and DELETE (OLD)
    DECLARE
        target_train_id UUID := COALESCE(NEW.train_id, OLD.train_id);
    BEGIN
        -- Check for active GROUNDED events
        SELECT EXISTS (
            SELECT 1 FROM unavailability_events
            WHERE train_id = target_train_id
            AND status = 'ACTIVE'
            AND restriction_level = 'GROUNDED'
        ) INTO has_grounded;

        -- Check for active RESTRICTED events
        SELECT EXISTS (
            SELECT 1 FROM unavailability_events
            WHERE train_id = target_train_id
            AND status = 'ACTIVE'
            AND restriction_level = 'RESTRICTED'
        ) INTO has_restricted;

        -- Determine new fitness status (priority order)
        IF has_grounded THEN
            new_status := 'GROUNDED';
        ELSIF has_restricted THEN
            new_status := 'RESTRICTED';
        ELSE
            new_status := 'FIT';
        END IF;

        -- Update train only if status changed
        UPDATE trains
        SET fitness_status = new_status,
            updated_at = NOW()
        WHERE id = target_train_id
        AND fitness_status IS DISTINCT FROM new_status;

        RETURN COALESCE(NEW, OLD);
    END;
END;
$$ LANGUAGE plpgsql;

-- Trigger for unavailability_events changes
DROP TRIGGER IF EXISTS trg_sync_train_fitness ON unavailability_events;
CREATE TRIGGER trg_sync_train_fitness
    AFTER INSERT OR UPDATE OR DELETE ON unavailability_events
    FOR EACH ROW
    EXECUTE FUNCTION sync_train_fitness_from_unavailability();

-- =============================================================================
-- MATERIALIZED VIEW REFRESH (CONCURRENT)
-- =============================================================================

-- Refresh all canvas-related materialized views concurrently
-- Called by scheduled job or on-demand via API
CREATE OR REPLACE FUNCTION refresh_canvas_views()
RETURNS VOID AS $$
BEGIN
    -- Refresh strategic canvas view (yearly aggregates)
    IF EXISTS (
        SELECT 1 FROM pg_matviews WHERE matviewname = 'v_canvas_strategic'
    ) THEN
        REFRESH MATERIALIZED VIEW CONCURRENTLY v_canvas_strategic;
    END IF;

    -- Refresh tactical canvas view (weekly details)
    IF EXISTS (
        SELECT 1 FROM pg_matviews WHERE matviewname = 'v_canvas_tactical'
    ) THEN
        REFRESH MATERIALIZED VIEW CONCURRENTLY v_canvas_tactical;
    END IF;

    -- Note: v_manhour_canvas and v_drift_canvas are regular views (not materialized)
    -- They don't need refresh as they query live data

    RAISE NOTICE 'Canvas views refreshed at %', NOW();
END;
$$ LANGUAGE plpgsql;

-- =============================================================================
-- SCENARIO EXPIRATION CLEANUP
-- =============================================================================

-- Clean up expired scenarios (30-day inactivity default)
-- Called by scheduled job (e.g., daily at 2 AM)
CREATE OR REPLACE FUNCTION cleanup_expired_scenarios()
RETURNS INTEGER AS $$
DECLARE
    deleted_count INTEGER;
BEGIN
    -- Mark expired scenarios as EXPIRED
    WITH expired AS (
        UPDATE scenarios
        SET status = 'EXPIRED',
            updated_at = NOW()
        WHERE status = 'ACTIVE'
        AND expires_at < NOW()
        RETURNING id
    )
    SELECT COUNT(*) INTO deleted_count FROM expired;

    -- Delete scenario deltas for expired scenarios older than 90 days
    -- (keep for audit trail for 90 days after expiration)
    DELETE FROM scenario_deltas
    WHERE scenario_id IN (
        SELECT id FROM scenarios
        WHERE status = 'EXPIRED'
        AND expires_at < NOW() - INTERVAL '90 days'
    );

    -- Log cleanup action
    IF deleted_count > 0 THEN
        INSERT INTO audit_log (
            entity_type, entity_id, action, details, created_at
        ) VALUES (
            'scenario',
            '00000000-0000-0000-0000-000000000000'::UUID,
            'BULK_EXPIRE',
            jsonb_build_object('expired_count', deleted_count),
            NOW()
        );
    END IF;

    RETURN deleted_count;
END;
$$ LANGUAGE plpgsql;

-- =============================================================================
-- MATERIAL RESERVATION CLEANUP
-- =============================================================================

-- Release soft reservations that have expired
-- Soft reservations: quantity_reserved at 90 days, convert to hard at 14 days
CREATE OR REPLACE FUNCTION release_expired_reservations()
RETURNS INTEGER AS $$
DECLARE
    released_count INTEGER;
BEGIN
    -- Release SOFT reservations older than 90 days
    WITH released AS (
        UPDATE material_reservations
        SET status = 'EXPIRED',
            updated_at = NOW()
        WHERE reservation_type = 'SOFT'
        AND status = 'RESERVED'
        AND created_at < NOW() - INTERVAL '90 days'
        RETURNING id, inventory_position_id, quantity_reserved
    ),
    -- Update inventory positions to release reserved quantity
    inventory_updates AS (
        UPDATE inventory_positions ip
        SET quantity_reserved = ip.quantity_reserved - r.quantity_reserved,
            quantity_available = ip.quantity_available + r.quantity_reserved,
            updated_at = NOW()
        FROM released r
        WHERE ip.id = r.inventory_position_id
    )
    SELECT COUNT(*) INTO released_count FROM released;

    IF released_count > 0 THEN
        RAISE NOTICE 'Released % expired soft reservations', released_count;
    END IF;

    RETURN released_count;
END;
$$ LANGUAGE plpgsql;

-- =============================================================================
-- FLEET MILEAGE TARGET CALCULATION
-- =============================================================================

-- Recalculate target_mileage_km for all trains in a fleet
-- Used for fleet balancing: equalizes mileage across trains
CREATE OR REPLACE FUNCTION update_fleet_mileage_targets(p_fleet_id UUID)
RETURNS VOID AS $$
DECLARE
    fleet_avg_mileage NUMERIC;
    fleet_total_target NUMERIC;
    train_count INTEGER;
    target_per_train NUMERIC;
BEGIN
    -- Get fleet statistics
    SELECT
        AVG(current_mileage_km),
        SUM(current_mileage_km),
        COUNT(*)
    INTO fleet_avg_mileage, fleet_total_target, train_count
    FROM trains
    WHERE fleet_id = p_fleet_id
    AND fitness_status != 'GROUNDED';

    IF train_count = 0 THEN
        RAISE NOTICE 'No active trains in fleet %', p_fleet_id;
        RETURN;
    END IF;

    -- Calculate target: aim for equal distribution
    -- Target = fleet average (equalizes wear across fleet)
    target_per_train := ROUND(fleet_avg_mileage);

    -- Update all trains in fleet
    UPDATE trains
    SET target_mileage_km = target_per_train,
        updated_at = NOW()
    WHERE fleet_id = p_fleet_id
    AND fitness_status != 'GROUNDED';

    RAISE NOTICE 'Updated % trains in fleet % with target mileage %',
        train_count, p_fleet_id, target_per_train;
END;
$$ LANGUAGE plpgsql;

-- =============================================================================
-- PM HIERARCHY SATISFACTION
-- =============================================================================

-- When a higher PM (e.g., C4) is completed, satisfy lower PMs (C1, C2, C3)
-- This resets the lower PM counters as per PM hierarchy rules
CREATE OR REPLACE FUNCTION apply_pm_hierarchy_satisfaction()
RETURNS TRIGGER AS $$
DECLARE
    satisfied_codes TEXT[];
    pm_code TEXT;
BEGIN
    -- Only trigger on PM completion
    IF NEW.status != 'COMPLETED' OR OLD.status = 'COMPLETED' THEN
        RETURN NEW;
    END IF;

    -- Get satisfies_codes for this PM type
    SELECT pt.satisfies_codes, pt.pm_code
    INTO satisfied_codes, pm_code
    FROM pm_types pt
    WHERE pt.id = NEW.pm_type_id;

    IF satisfied_codes IS NULL OR array_length(satisfied_codes, 1) IS NULL THEN
        RETURN NEW;
    END IF;

    -- Update pm_tracking for all satisfied PM types
    UPDATE pm_tracking
    SET last_pm_date = NEW.actual_completion_date,
        last_pm_mileage_km = NEW.actual_mileage_km,
        updated_at = NOW()
    WHERE train_id = NEW.train_id
    AND pm_type_id IN (
        SELECT id FROM pm_types
        WHERE pm_code = ANY(satisfied_codes)
        AND fleet_id = (
            SELECT fleet_id FROM trains WHERE id = NEW.train_id
        )
    );

    -- Log the cascade
    INSERT INTO audit_log (
        entity_type, entity_id, action, user_id, details, created_at
    ) VALUES (
        'pm_schedule', NEW.id, 'PM_HIERARCHY_CASCADE',
        NEW.completed_by,
        jsonb_build_object(
            'source_pm', pm_code,
            'satisfied_pms', satisfied_codes,
            'train_id', NEW.train_id
        ),
        NOW()
    );

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Trigger for PM schedule completion
DROP TRIGGER IF EXISTS trg_pm_hierarchy_satisfaction ON pm_schedule;
CREATE TRIGGER trg_pm_hierarchy_satisfaction
    AFTER UPDATE ON pm_schedule
    FOR EACH ROW
    EXECUTE FUNCTION apply_pm_hierarchy_satisfaction();

-- =============================================================================
-- AUDIT TRAIL TRIGGERS
-- =============================================================================

-- Automatic audit logging for pm_schedule changes
CREATE OR REPLACE FUNCTION audit_pm_schedule_changes()
RETURNS TRIGGER AS $$
BEGIN
    INSERT INTO pm_schedule_history (
        pm_schedule_id,
        change_type,
        old_values,
        new_values,
        changed_by,
        change_reason,
        created_at
    ) VALUES (
        COALESCE(NEW.id, OLD.id),
        TG_OP,
        CASE WHEN TG_OP IN ('UPDATE', 'DELETE') THEN to_jsonb(OLD) ELSE NULL END,
        CASE WHEN TG_OP IN ('INSERT', 'UPDATE') THEN to_jsonb(NEW) ELSE NULL END,
        COALESCE(NEW.updated_by, OLD.updated_by, current_setting('app.current_user_id', TRUE)::UUID),
        current_setting('app.change_reason', TRUE),
        NOW()
    );

    RETURN COALESCE(NEW, OLD);
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_audit_pm_schedule ON pm_schedule;
CREATE TRIGGER trg_audit_pm_schedule
    AFTER INSERT OR UPDATE OR DELETE ON pm_schedule
    FOR EACH ROW
    EXECUTE FUNCTION audit_pm_schedule_changes();

-- =============================================================================
-- VERIFICATION
-- =============================================================================

DO $$
DECLARE
    func_count INTEGER;
    trigger_count INTEGER;
BEGIN
    -- Verify functions exist
    SELECT COUNT(*) INTO func_count
    FROM pg_proc
    WHERE proname IN (
        'update_updated_at_column',
        'sync_train_fitness_from_unavailability',
        'refresh_canvas_views',
        'cleanup_expired_scenarios',
        'release_expired_reservations',
        'update_fleet_mileage_targets',
        'apply_pm_hierarchy_satisfaction',
        'audit_pm_schedule_changes'
    );

    IF func_count < 8 THEN
        RAISE WARNING 'Not all functions created. Expected 8, found %', func_count;
    END IF;

    -- Verify triggers exist
    SELECT COUNT(*) INTO trigger_count
    FROM pg_trigger
    WHERE tgname IN (
        'trg_sync_train_fitness',
        'trg_pm_hierarchy_satisfaction',
        'trg_audit_pm_schedule'
    );

    IF trigger_count < 3 THEN
        RAISE WARNING 'Not all triggers created. Expected 3, found %', trigger_count;
    END IF;

    RAISE NOTICE 'Database functions and triggers verified: % functions, % triggers',
        func_count, trigger_count;
END $$;

