   321→export type NewBaselinePmSchedule = InferInsertModel<typeof baselinePmSchedule>;
   322→export type BaselineMileageProjection = InferSelectModel<typeof baselineMileageProjection>;
   323→export type NewBaselineMileageProjection = InferInsertModel<typeof baselineMileageProjection>;
   324→export type DriftAnalysis = InferSelectModel<typeof driftAnalysis>;
   325→export type NewDriftAnalysis = InferInsertModel<typeof driftAnalysis>;
