/**
 * MMS Mileage Tracking Tables
 *
 * Time-series odometer data and meter events.
 * Uses TimescaleDB hypertable for efficient storage and querying.
 *
 * Data flow:
 * 1. CSV file arrives via file watcher
 * 2. Ingestion worker validates and inserts into mileage_readings
 * 3. Anomaly detection flags suspicious readings
 * 4. Meter events track odometer replacements/resets
 *
 * @see specs/003-database-schema.md Section 3.3
 */

import { relations } from 'drizzle-orm';
import {
  date,
  index,
  integer,
  pgTable,
  primaryKey,
  text,
  timestamp,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { trains } from './core-fleet';
import { anomalyTypeEnum, meterEventTypeEnum, validationStatusEnum } from './enums';
import { users } from './users';

/**
 * Meter Events - Odometer replacements, resets, calibrations
 *
 * Tracks events that affect mileage continuity:
 * - REPLACEMENT: New meter installed
 * - RESET: Meter zeroed
 * - CALIBRATION: Meter adjusted
 * - SWAP: Meter moved between trains
 *
 * The adjustment_km field represents the cumulative mileage that must be
 * added to all subsequent readings to maintain accurate lifetime mileage.
 */
export const meterEvents = pgTable(
  'meter_events',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    eventDate: date('event_date').notNull(),
    eventType: meterEventTypeEnum('event_type').notNull(),

    oldMeterSerial: varchar('old_meter_serial', { length: 50 }),
    newMeterSerial: varchar('new_meter_serial', { length: 50 }),
    oldMeterReading: integer('old_meter_reading'),
    newMeterReading: integer('new_meter_reading'),
    adjustmentKm: integer('adjustment_km'), // Cumulative adjustment to apply

    reason: text('reason'),
    approvedBy: uuid('approved_by').references(() => users.id),
    approvedAt: timestamp('approved_at', { withTimezone: true }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by').references(() => users.id),
  },
  (table) => [index('idx_meter_events_train').on(table.trainId, table.eventDate)]
);

/**
 * Mileage Readings - Daily odometer readings
 *
 * This table is designed for TimescaleDB hypertable conversion:
 * - Partitioned by reading_date (7-day chunks)
 * - Compressed after 30 days
 * - Retained for 13 years (contract + buffer)
 *
 * Key fields:
 * - raw_reading: Direct value from CSV
 * - adjusted_reading: After meter event adjustments
 * - daily_km: Calculated as today - yesterday
 * - validation_status: PENDING -> VALID | ANOMALY -> CORRECTED
 *
 * Note: In production, this table should be converted to a TimescaleDB
 * hypertable with:
 * SELECT create_hypertable('mileage_readings', 'reading_date');
 */
export const mileageReadings = pgTable(
  'mileage_readings',
  {
    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    readingDate: date('reading_date').notNull(),

    // Raw and adjusted values
    rawReading: integer('raw_reading').notNull(), // Direct from CSV
    adjustedReading: integer('adjusted_reading').notNull(), // After meter adjustments
    dailyKm: integer('daily_km'), // Calculated: today - yesterday

    // Validation
    validationStatus: validationStatusEnum('validation_status').default('PENDING'),
    anomalyType: anomalyTypeEnum('anomaly_type'),
    anomalyNotes: text('anomaly_notes'),

    // Source tracking
    sourceFile: varchar('source_file', { length: 255 }),
    meterEventId: uuid('meter_event_id').references(() => meterEvents.id),

    ingestedAt: timestamp('ingested_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    primaryKey({ columns: [table.trainId, table.readingDate] }),
    index('idx_mileage_train_date').on(table.trainId, table.readingDate),
    index('idx_mileage_validation').on(table.validationStatus, table.readingDate),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const meterEventsRelations = relations(meterEvents, ({ one, many }) => ({
  train: one(trains, {
    fields: [meterEvents.trainId],
    references: [trains.id],
  }),
  approvedByUser: one(users, {
    fields: [meterEvents.approvedBy],
    references: [users.id],
    relationName: 'approvedBy',
  }),
  createdByUser: one(users, {
    fields: [meterEvents.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
  mileageReadings: many(mileageReadings),
}));

export const mileageReadingsRelations = relations(mileageReadings, ({ one }) => ({
  train: one(trains, {
    fields: [mileageReadings.trainId],
    references: [trains.id],
  }),
  meterEvent: one(meterEvents, {
    fields: [mileageReadings.meterEventId],
    references: [meterEvents.id],
  }),
}));

/**
 * MMS Baseline & Drift Tables
 *
 * Plan stability through immutable baseline snapshots and drift monitoring.
 *
 * Baseline/Drift Architecture:
 * - Baselines are published snapshots of the PM schedule and mileage projections
 * - Drift analysis compares current state to baseline
 * - When drift exceeds thresholds, requires_replan flag is set
 *
 * Drift thresholds:
 * - Mileage: ±5.0%
 * - Schedule: ±14 days
 * - Fleet: ≥5 trains requiring replan
 *
 * @see specs/003-database-schema.md Section 3.8
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots, trains } from './core-fleet';
import { baselineStatusEnum } from './enums';
import { pmTypes } from './pm-management';
import { users } from './users';

/**
 * Plan Baselines - Immutable schedule snapshots
 *
 * A baseline captures the state of PM scheduling and mileage projections
 * at a point in time. Published baselines become the reference for drift analysis.
 *
 * Status lifecycle:
 * DRAFT -> PUBLISHED -> SUPERSEDED (when new baseline published)
 */
export const planBaselines = pgTable(
  'plan_baselines',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    description: text('description'),
    version: varchar('version', { length: 20 }).notNull(), // 'v3.2'

    baselineDate: date('baseline_date').notNull(), // "As of" date
    horizonEnd: date('horizon_end').notNull(), // How far into future

    // Workflow
    status: baselineStatusEnum('status').default('DRAFT'),
    createdBy: uuid('created_by')
      .notNull()
      .references(() => users.id),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),

    publishedBy: uuid('published_by').references(() => users.id),
    publishedAt: timestamp('published_at', { withTimezone: true }),

    supersededBy: uuid('superseded_by'),
    supersededAt: timestamp('superseded_at', { withTimezone: true }),

    // Metrics at baseline time
    fleetCount: integer('fleet_count'),
    totalPmScheduled: integer('total_pm_scheduled'),
    totalManhourProjected: decimal('total_manhour_projected', { precision: 12, scale: 2 }),
  },
  (table) => [
    index('idx_baselines_status').on(table.status),
    index('idx_baselines_date').on(table.baselineDate),
  ]
);

/**
 * Baseline PM Schedule - Snapshot of scheduled maintenance
 *
 * Immutable copy of PM schedule at baseline time.
 * Used for drift comparison.
 */
export const baselinePmSchedule = pgTable(
  'baseline_pm_schedule',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),
    projectedDate: date('projected_date').notNull(),
    projectedMileageKm: integer('projected_mileage_km'),

    assignedDepotId: uuid('assigned_depot_id').references(() => depots.id),
    assignedHours: decimal('assigned_hours', { precision: 6, scale: 2 }),
  },
  (table) => [
    uniqueIndex('idx_baseline_pm_unique').on(
      table.baselineId,
      table.trainId,
      table.pmTypeId,
      table.projectedDate
    ),
    index('idx_baseline_pm_baseline').on(table.baselineId),
    index('idx_baseline_pm_train').on(table.trainId, table.projectedDate),
  ]
);

/**
 * Baseline Mileage Projection - Snapshot of mileage forecasts
 *
 * Immutable copy of mileage projections at baseline time.
 * Used for drift comparison.
 */
export const baselineMileageProjection = pgTable(
  'baseline_mileage_projection',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    projectionDate: date('projection_date').notNull(),
    projectedCumulativeKm: integer('projected_cumulative_km').notNull(),
    dailyRateKm: integer('daily_rate_km'), // Assumed daily accrual rate
  },
  (table) => [
    uniqueIndex('idx_baseline_mileage_unique').on(
      table.baselineId,
      table.trainId,
      table.projectionDate
    ),
    index('idx_baseline_mileage').on(table.baselineId, table.trainId),
  ]
);

/**
 * Drift Analysis - Comparison results
 *
 * Generated by drift monitor (nightly job).
 * Compares current state to baseline and flags trains requiring replan.
 */
export const driftAnalysis = pgTable(
  'drift_analysis',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id),
    analysisDate: date('analysis_date').notNull(),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),

    // Mileage drift
    baselineProjectedKm: integer('baseline_projected_km').notNull(),
    actualKm: integer('actual_km').notNull(),
    // mileage_drift_km = actual - baseline (calculated in queries)
    mileageDriftPct: decimal('mileage_drift_pct', { precision: 5, scale: 2 }),

    // Schedule drift (days)
    avgPmDriftDays: decimal('avg_pm_drift_days', { precision: 5, scale: 1 }),
    maxPmDriftDays: integer('max_pm_drift_days'),

    // Threshold breach
    requiresReplan: boolean('requires_replan').default(false),
    replanReason: text('replan_reason'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_drift_unique').on(table.baselineId, table.trainId, table.analysisDate),
    index('idx_drift_baseline').on(table.baselineId, table.analysisDate),
    index('idx_drift_replan').on(table.requiresReplan, table.analysisDate),
  ]
);

