/**
 * MMS Audit & History Tables
 *
 * Immutable audit trail for compliance with 12-year government contract.
 * All PM schedule changes and significant actions are logged.
 *
 * Key requirements:
 * - Full attribution (who, when, why)
 * - Before/after values for all changes
 * - Optimizer decisions must include explanation traces
 * - Compliance flags for safety-critical changes
 *
 * @see specs/003-database-schema.md Section 3.11
 */

import { relations } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  inet,
  jsonb,
  pgTable,
  text,
  timestamp,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { auditActionEnum, changeSourceEnum, pmChangeTypeEnum, pmStatusEnum } from './enums';
import { pmSchedule } from './pm-management';
import { users } from './users';

/**
 * PM Schedule History - Detailed change tracking for PM records
 *
 * Every change to a PM schedule is logged here.
 * Includes optimizer context when changes are suggested by the optimizer.
 *
 * Change types:
 * - CREATED: New PM scheduled
 * - DATE_CHANGED: Target date moved
 * - STATUS_CHANGED: Status transition
 * - TRACK_ASSIGNED: Track allocation changed
 * - LOCKED/UNLOCKED: Lock state changed
 * - COMPLETED/CANCELLED/DEFERRED: Terminal states
 */
export const pmScheduleHistory = pgTable(
  'pm_schedule_history',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmScheduleId: uuid('pm_schedule_id')
      .notNull()
      .references(() => pmSchedule.id),

    changeType: pmChangeTypeEnum('change_type').notNull(),

    // Previous values
    oldTargetDate: date('old_target_date'),
    oldStatus: pmStatusEnum('old_status'),
    oldAssignedTrackId: uuid('old_assigned_track_id'),
    oldAssignedHours: decimal('old_assigned_hours', { precision: 6, scale: 2 }),

    // New values
    newTargetDate: date('new_target_date'),
    newStatus: pmStatusEnum('new_status'),
    newAssignedTrackId: uuid('new_assigned_track_id'),
    newAssignedHours: decimal('new_assigned_hours', { precision: 6, scale: 2 }),

    // Attribution
    changedBy: uuid('changed_by')
      .notNull()
      .references(() => users.id),
    changedAt: timestamp('changed_at', { withTimezone: true }).defaultNow(),
    changeReason: text('change_reason'),
    changeSource: changeSourceEnum('change_source').default('USER'),

    // Optimizer context (if change was suggested by optimizer)
    optimizerRequestId: uuid('optimizer_request_id'),
    optimizerExplanation: jsonb('optimizer_explanation'),
  },
  (table) => [
    index('idx_pm_history_schedule').on(table.pmScheduleId, table.changedAt),
    index('idx_pm_history_date').on(table.changedAt),
    index('idx_pm_history_user').on(table.changedBy, table.changedAt),
  ]
);

/**
 * Audit Log - General system audit trail
 *
 * Captures all significant actions across the system.
 * Used for compliance reporting and investigation.
 *
 * Actions:
 * - CREATE, UPDATE, DELETE: Data modifications
 * - APPROVE, REJECT: Workflow decisions
 * - PUBLISH: Baseline publication
 */
export const auditLog = pgTable(
  'audit_log',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // What
    entityType: varchar('entity_type', { length: 50 }).notNull(), // 'pm_schedule', 'baseline', etc.
    entityId: uuid('entity_id').notNull(),
    action: auditActionEnum('action').notNull(),

    // Who
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id),
    userEmail: varchar('user_email', { length: 255 }),
    userIpAddress: inet('user_ip_address'),

    // When
    occurredAt: timestamp('occurred_at', { withTimezone: true }).defaultNow(),

    // Details
    oldValues: jsonb('old_values'),
    newValues: jsonb('new_values'),
    metadata: jsonb('metadata'), // Additional context

    // Compliance
    complianceFlags: text('compliance_flags').array(), // ['SAFETY_CRITICAL', 'FINANCIAL']
  },
  (table) => [
    index('idx_audit_entity').on(table.entityType, table.entityId, table.occurredAt),
    index('idx_audit_user').on(table.userId, table.occurredAt),
    index('idx_audit_date').on(table.occurredAt),
  ]
);

